INSERT INTO articles (title, slug, summary, content, threat_level, category, cves, affected_products, threat_actors, industries, attack_vector, source, source_url, published_at, updated_at, discovered_at, exploited_at, patched_at, verified, verified_by, tags, region) VALUES
('UNC3886 Deploys Firmware Rootkit on Juniper MX Routers via Zero-Day', 'unc3886-juniper-mx-firmware-rootkit', 'UNC3886 exploits Juniper Junos zero-day to deploy firmware-level rootkits on MX-series routers. Implant survives software upgrades and factory resets.', 'Mandiant identified UNC3886 exploiting CVE-2026-29001 in Juniper Junos OS to install firmware-level rootkits on MX-series routers used by ISPs and large enterprises. The implant, dubbed TinyShell.Router, intercepts and exfiltrates network traffic while maintaining persistence across software upgrades. Discovery came during an IR engagement at a European telecom.', 'critical', 'zero-day', '{"CVE-2026-29001"}', '{"Juniper MX Series","Juniper Junos OS","ISP Core Routers"}', '{"UNC3886"}', '{"telecommunications","government","defense","technology"}', 'Network / Junos OS Management Interface', 'Mandiant', 'https://www.mandiant.com', '2026-03-31T10:00:00Z', '2026-04-01T06:00:00Z', '2026-03-20T00:00:00Z', '2026-03-20T00:00:00Z', NULL, true, '{"Mandiant","CISA","Juniper"}', '{"zero-day","firmware","rootkit","juniper","unc3886","network-edge"}', 'Global'),

('UNC3886 Linked to VMware vCenter Exploitation Campaign Targeting Defense Sector', 'unc3886-vcenter-defense-exploitation', 'UNC3886 exploits known VMware vCenter vulnerabilities to deploy VirtualPita and VirtualPie backdoors across defense contractor virtualization infrastructure.', 'UNC3886 has been observed exploiting patched VMware vCenter Server vulnerabilities at organizations that failed to update. The group deploys VirtualPita and VirtualPie malware on ESXi hypervisors, operating below the OS layer where EDR cannot detect them. Current campaign targets US and allied defense industrial base companies managing classified workloads.', 'high', 'apt', '{"CVE-2025-22224","CVE-2025-22225"}', '{"VMware vCenter Server","VMware ESXi","vSphere"}', '{"UNC3886"}', '{"defense","government","technology"}', 'VMware vCenter Exploitation', 'Mandiant / Microsoft', 'https://www.mandiant.com', '2026-03-15T08:00:00Z', '2026-03-16T12:00:00Z', '2026-02-20T00:00:00Z', '2026-02-20T00:00:00Z', NULL, true, '{"Mandiant","Microsoft","CISA"}', '{"vmware","vcenter","hypervisor","defense","unc3886"}', 'United States / Allied Nations'),

('Sandworm Targets European Energy Companies with Industroyer3 Variant', 'sandworm-industroyer3-european-energy', 'Sandworm deploys Industroyer3 variant against energy companies in Poland and Baltic states. ICS-specific payload targets Siemens SIPROTEC relays.', 'CERT-EU and Mandiant have identified Sandworm deploying an updated variant of Industroyer malware targeting energy transmission companies in Poland, Lithuania, and Estonia. The malware includes ICS-specific modules targeting Siemens SIPROTEC protective relays and ABB RTU560 devices. Attack appears timed to coincide with geopolitical tensions in the region.', 'critical', 'malware', '{}', '{"Siemens SIPROTEC","ABB RTU560","Energy SCADA","ICS Networks"}', '{"Sandworm"}', '{"energy","government"}', 'ICS Protocol Exploitation / Destructive Malware', 'CERT-EU / Mandiant', 'https://cert.europa.eu', '2026-03-25T06:00:00Z', '2026-03-26T10:00:00Z', '2026-03-22T00:00:00Z', '2026-03-22T00:00:00Z', NULL, true, '{"CERT-EU","Mandiant","ENISA"}', '{"industroyer","ics","energy","sandworm","destructive","europe"}', 'Europe'),

('Sandworm Uses Compromised Ubiquiti Routers as C2 Infrastructure', 'sandworm-ubiquiti-routers-c2', 'FBI warns Sandworm is using a botnet of compromised Ubiquiti EdgeRouters as proxy C2 infrastructure for espionage operations against NATO targets.', 'FBI advisory reveals Sandworm has compromised thousands of Ubiquiti EdgeRouters worldwide using default credentials and known vulnerabilities. The routers serve as proxy infrastructure for command-and-control communications, making it difficult to attribute network traffic back to Russian GRU operations. Targets include NATO military installations and European government networks.', 'high', 'malware', '{}', '{"Ubiquiti EdgeRouter","SOHO Routers","Linux-based Routers"}', '{"Sandworm"}', '{"government","defense","telecommunications"}', 'Default Credentials / Router Exploitation', 'FBI / NSA Joint Advisory', 'https://www.fbi.gov', '2026-03-08T14:00:00Z', '2026-03-09T10:00:00Z', '2026-02-01T00:00:00Z', NULL, NULL, true, '{"FBI","NSA","CISA"}', '{"botnet","routers","c2","sandworm","nato","proxy"}', 'Global'),

('APT29 Targets European Cloud Service Providers in Operation CloudJack', 'apt29-european-cloud-providers-cloudjack', 'APT29 compromises two European cloud hosting providers to access customer environments. Hundreds of EU government and enterprise tenants at risk.', 'Microsoft and ANSSI report that APT29 compromised administrative access at two mid-tier European cloud hosting providers, gaining potential access to hundreds of EU government and enterprise customer environments. The operation, dubbed CloudJack, used stolen admin OAuth tokens to move laterally through customer tenants. Affected providers have initiated incident response and customer notifications.', 'critical', 'apt', '{}', '{"European Cloud Platforms","Azure Stack","VMware Cloud","Customer Tenants"}', '{"APT29"}', '{"technology","government","finance"}', 'Cloud Admin Compromise / OAuth Token Theft', 'Microsoft / ANSSI', 'https://www.microsoft.com/security/blog', '2026-03-22T12:00:00Z', '2026-03-23T08:00:00Z', '2026-03-15T00:00:00Z', '2026-03-15T00:00:00Z', NULL, true, '{"Microsoft","ANSSI","ENISA"}', '{"cloud","apt29","oauth","service-provider","europe"}', 'Europe'),

('LockBit Affiliate Arrested — Europol Seizes $14M in Cryptocurrency', 'lockbit-affiliate-arrested-14m-seized', 'Europol arrests LockBit affiliate in Ukraine and seizes $14M in cryptocurrency. Suspect linked to attacks on 150+ organizations.', 'Europol, in coordination with FBI and Ukrainian cyber police, arrested a key LockBit affiliate responsible for deploying ransomware against over 150 organizations across 30 countries. Authorities seized $14 million in cryptocurrency, source code for custom LockBit variants, and decryption keys that may help victims recover data. The arrest is part of Operation Cronos ongoing disruption of the LockBit ecosystem.', 'low', 'ransomware', '{}', '{"N/A"}', '{"LockBit"}', '{"finance","healthcare","manufacturing","government"}', 'N/A — Law Enforcement Action', 'Europol / FBI', 'https://www.europol.europa.eu', '2026-03-20T10:00:00Z', '2026-03-21T08:00:00Z', NULL, NULL, NULL, true, '{"Europol","FBI","Ukrainian Cyber Police"}', '{"law-enforcement","lockbit","arrest","cryptocurrency","operation-cronos"}', 'Europe / Global'),

('Scattered Spider Uses AI Voice Cloning to Bypass Voice-Based MFA', 'scattered-spider-ai-voice-cloning-mfa', 'Scattered Spider adopts AI voice cloning to defeat voice verification MFA at financial institutions. Three banks confirm successful bypass.', 'Scattered Spider has adopted AI voice cloning technology to defeat voice-based multi-factor authentication used by financial institutions. Attackers clone customer voices from social media and publicly available audio, then use the cloned voices to authenticate to banking systems via phone. Three major banks have confirmed successful MFA bypass incidents. Industry group recommends transitioning away from voice-based authentication.', 'high', 'phishing', '{}', '{"Voice MFA Systems","Banking Authentication","AI Voice Cloning"}', '{"Scattered Spider"}', '{"finance","technology"}', 'AI Voice Cloning / Voice MFA Bypass', 'FS-ISAC', 'https://www.fsisac.com', '2026-03-16T13:00:00Z', '2026-03-17T10:00:00Z', '2026-03-10T00:00:00Z', '2026-03-10T00:00:00Z', NULL, true, '{"FS-ISAC","FBI"}', '{"ai","voice-cloning","mfa-bypass","finance","scattered-spider"}', 'United States'),

('Volt Typhoon Compromises US Natural Gas Pipeline Operator OT Networks', 'volt-typhoon-natural-gas-pipeline-ot', 'Volt Typhoon confirmed inside OT networks of a major US natural gas pipeline operator. Access to safety instrumented systems raises explosion risk concerns.', 'CISA emergency advisory confirms Volt Typhoon has gained access to operational technology networks at a major US natural gas pipeline operator. Investigators found evidence of access to safety instrumented systems (SIS) that control emergency shutdowns. While no manipulation was detected, the access level raises serious concerns about potential kinetic impacts. TSA issued an emergency security directive requiring enhanced monitoring.', 'critical', 'apt', '{}', '{"Pipeline SCADA","Safety Instrumented Systems","Gas Chromatographs","OT Networks"}', '{"Volt Typhoon"}', '{"energy","government"}', 'IT-OT Lateral Movement / OT Credential Reuse', 'CISA / TSA Emergency Directive', 'https://www.cisa.gov', '2026-03-28T08:00:00Z', '2026-03-29T06:00:00Z', '2024-01-01T00:00:00Z', '2024-01-01T00:00:00Z', NULL, true, '{"CISA","TSA","DOE","FBI"}', '{"critical-infrastructure","pipeline","ot-security","volt-typhoon","natural-gas"}', 'United States'),

('Lazarus Group Targets DeFi Protocols with New Smart Contract Exploit Kit', 'lazarus-defi-smart-contract-exploit-kit', 'Lazarus Group deploys modular smart contract exploit toolkit targeting DeFi protocols. $200M stolen across four platforms in March.', 'Chainalysis and SlowMist report that Lazarus Group has developed a modular toolkit for exploiting DeFi smart contracts, focusing on flash loan vulnerabilities, oracle manipulation, and cross-chain bridge weaknesses. Four DeFi protocols lost a combined $200M in March. The toolkit automates vulnerability scanning of deployed contracts and generates custom exploits.', 'high', 'data-breach', '{}', '{"DeFi Protocols","Smart Contracts","Cross-chain Bridges","Oracle Networks"}', '{"Lazarus Group"}', '{"finance","technology"}', 'Smart Contract Exploitation / Flash Loans', 'Chainalysis / SlowMist', 'https://www.chainalysis.com', '2026-03-27T15:00:00Z', '2026-03-28T10:00:00Z', '2026-03-05T00:00:00Z', '2026-03-05T00:00:00Z', NULL, true, '{"Chainalysis","SlowMist","FBI"}', '{"defi","cryptocurrency","smart-contract","lazarus","flash-loan"}', 'Global'),

('Black Basta Internal Chat Logs Leaked — Reveal Operations and Targets', 'black-basta-chat-logs-leaked', 'Leaked internal communications from Black Basta ransomware group reveal operational structure, target selection process, and connections to former Conti members.', 'A cache of internal chat logs from the Black Basta ransomware group has been leaked online, revealing detailed operational insights. The logs confirm connections to former Conti ransomware operators, show systematic target selection based on company revenue and cyber insurance status, and reveal internal disputes over ransom payment handling. The leak includes victim negotiation transcripts and technical details of their tooling.', 'medium', 'ransomware', '{}', '{"N/A"}', '{"Black Basta"}', '{"technology","finance","healthcare","manufacturing"}', 'N/A — Intelligence Leak', 'Prodaft / VX-Underground', 'https://www.prodaft.com', '2026-03-04T11:00:00Z', '2026-03-05T08:00:00Z', NULL, NULL, NULL, true, '{"Prodaft"}', '{"ransomware","leak","black-basta","conti","threat-intelligence"}', 'Global'),

('APT28 Exploits Cisco Router Vulnerabilities for Long-Term Espionage', 'apt28-cisco-router-espionage', 'UK NCSC warns APT28 exploiting Cisco router vulnerabilities to establish persistent espionage infrastructure across European government networks.', 'The UK National Cyber Security Centre and US NSA issued a joint advisory warning that APT28 has been exploiting CVE-2026-20145 and older Cisco IOS vulnerabilities to install GRU-developed malware on routers used by European government agencies. The malware, named Jaguar Tooth, enables undetected SNMP-based data exfiltration. Campaign has been active for at least 6 months.', 'high', 'apt', '{"CVE-2026-20145"}', '{"Cisco IOS","Cisco ISR Routers","Cisco ASR Routers"}', '{"APT28"}', '{"government","defense","telecommunications"}', 'Router Exploitation / SNMP Exfiltration', 'UK NCSC / NSA', 'https://www.ncsc.gov.uk', '2026-03-11T09:00:00Z', '2026-03-12T07:00:00Z', '2025-09-01T00:00:00Z', '2025-09-01T00:00:00Z', NULL, true, '{"UK NCSC","NSA","CISA"}', '{"apt28","cisco","router","espionage","snmp","europe"}', 'Europe'),

('Cl0p Claims 200 New Victims from Cleo Campaign — Threatens Mass Data Release', 'cl0p-200-victims-cleo-mass-release', 'Cl0p adds 200 organizations to its leak site from the Cleo file transfer campaign. Threatens mass data release starting April 1 if ransoms unpaid.', 'Cl0p has listed 200 organizations on its leak site as victims of the Cleo Harmony/VLTrader exploitation campaign and set an April 1 deadline for mass data release. Victims span financial services, healthcare, retail, and government sectors across 25 countries. Several victims have confirmed data exfiltration. The scale of this campaign approaches Cl0p''s 2023 MOVEit operation which affected over 2,500 organizations.', 'high', 'data-breach', '{}', '{"Cleo Harmony","Cleo VLTrader","Enterprise File Transfer"}', '{"Cl0p"}', '{"finance","healthcare","retail","government","manufacturing"}', 'Data Exfiltration / Extortion', 'BleepingComputer / Cl0p Leak Site', 'https://www.bleepingcomputer.com', '2026-03-29T11:00:00Z', '2026-03-30T09:00:00Z', NULL, NULL, NULL, true, '{"BleepingComputer","CISA"}', '{"cl0p","cleo","data-leak","extortion","mass-exploitation"}', 'Global');
